fn urgency_for_score(score: f64) -> UrgencyLevel {
    if score >= 0.95 {
        UrgencyLevel::Critical
    } else if score >= 0.8 {
        UrgencyLevel::High
    } else if score >= 0.5 {
        UrgencyLevel::Medium
    } else {
        UrgencyLevel::Low
    }
}

fn normalize_text(value: &str) -> String {
    value
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .to_lowercase()
}

