            let offset_idx = params_vec.len() + 2;
            sql.push_str(&format!(
                " ORDER BY i.score DESC LIMIT ?{limit_idx} OFFSET ?{offset_idx}"
            ));
            params_vec.push(Box::new(limit as i64));
