        let response = request
            .send()
            .await
            .map_err(|e| PublishError::Http(e.to_string()))?;
        let status = response.status();
        if !status.is_success() {
            let body = response.text().await.unwrap_or_default();
            return Err(PublishError::Http(format!("{status}: {body}")));
        }

