    "system_prompt",
    "bootstrap",
    "execution",
    "verification",
    "failure_recovery",
}
LIST_SURFACES = {"tools", "skills", "memory_sources", "subagents"}
POLICY_SURFACES = {"runtime_policy"}
EDITABLE_SURFACES = TEXT_SURFACES | LIST_SURFACES | POLICY_SURFACES
OP_WHITELIST = {"AppendToListSurface", "AppendToSurface", "ReplaceSurface", "SetPolicy"}
SURFACE_KINDS = {
    **{surface: "text" for surface in TEXT_SURFACES},
    **{surface: "list" for surface in LIST_SURFACES},
    "runtime_policy": "policy",
}


def initial_harness() -> HarnessSpec:
    return HarnessSpec(
        system_prompt="You are a careful terminal agent.",
        bootstrap="Read the task before acting.",
        execution="Use the available environment conservatively.",
        verification="Check the final answer before finishing.",
        failure_recovery="If something fails, inspect the error.",
